function handleSteamUserAuthentication(statusCode, response)
{
	if (statusCode === 200)
	{
		var responseJson = JSON.parse(response);

		// Set session ID
		g_sessionID = responseJson.sessionid;

		// Set cookies
		setCookie("sessionid", g_sessionID);
		setCookie("steamlogin", responseJson.logincomplete, 30);
	}
	else
	{
		// Request a new login key
		Steam.requestLogin();
	}
}

