func GenerateRSAKeyPair(pubKeyFile, privKeyFile string, bits int) (err error) {
	var (
		pubKey  *rsa.PublicKey
		privKey *rsa.PrivateKey
	)

	// generate key pair
	if pubKey, privKey, err = GenerateRSAPemPair(bits); err == nil {
		// save private key
		var privKeyOut *os.File
		if privKeyOut, err = os.OpenFile(privKeyFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600); err == nil {
			defer privKeyOut.Close()

			// write PEM encoded private key to file
			if err = pem.Encode(privKeyOut, &pem.Block{Type: "RSA PRIVATE KEY", Bytes: x509.MarshalPKCS1PrivateKey(privKey)}); err == nil {
				// save public key
				var pubKeyOut *os.File
				if pubKeyOut, err = os.OpenFile(pubKeyFile, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0644); err == nil {
					defer pubKeyOut.Close()
					// write PEM encoded public key to file
					pubKeyBytes := x509.MarshalPKCS1PublicKey(pubKey)
					if err = pem.Encode(pubKeyOut, &pem.Block{Type: "RSA PUBLIC KEY", Bytes: pubKeyBytes}); err == nil {
						return
					}
				}
			}
		}
	}
	return
}

