func GeneratePrivateKey(typ string, bitSize int, rand io.Reader) (interface{}, error) {
       switch typ {
       case "RSA":
               return rsa.GenerateKey(rand, bitSize)
       case "ECDSA":
               if bitSize == 0 {
                       bitSize = 256
               }
               return ecdsa.GenerateKey(elliptic.P256(), rand)
       case "ED25519":
               if rand == nil {
                       rand = rand.Reader
                 }
               _, err := rand.Read(make([]byte, 32))
               if err != nil {
                       return nil, errors.New("ed25519: failed to read random seed: " + err.Error())
               }
               return ed25519.GenerateKey(rand)
       default:
               return nil, fmt.Errorf("unsupported private key type: %s", typ)
       }
   }

