	description := d.Get("description").(string)
	roleType := d.Get("role_type").(string)
	permissions := d.Get("permissions").(*schema.Set)
	keyId := d.Get("key_id").(string)

	role := &ssh.RoleV2{
		Name:        name,
		Description: description,
		RoleType:    ssh.RoleType(roleType),
		KeyId:       keyId,
	}

	if v, ok := d.GetOk("max_session_ttl"); ok {
		role.MaxSessionTTL = v.(string)
	}
	if v, ok := d.GetOk("max_sessions_per_user"); ok {
		role.MaxSessionsPerUser = v.(int)
	}
	if v, ok := d.GetOk("forward_agent"); ok {
		role.ForwardAgent = v.(bool)
	}
	if v, ok := d.GetOk("node_labels"); ok {
		role.NodeLabels = flattenStringList(v.(*schema.Set).List())
	}

	// Build the permissions
	permSet := permissions.(*schema.Set)
	role.Permissions = make([]*ssh.PermissionV2, permSet.Len())
	for i, perm := range permSet.List() {
		p := perm.(map[string]interface{})
		role.Permissions[i] = &ssh.PermissionV2{
			Type:          p["type"].(string),
			Resource:      p["resource"].(string),
			Actions:       utils.InterfaceSliceToStringSlice(p["actions"].(*schema.Set).List()),
			Effect:        p["effect"].(string),
			ConstraintIDs: utils.InterfaceSliceToIntSlice(p["constraint_ids"].(*schema.Set).List()),
		}
	}

	// Create or update the role
	if _, err := client.SSH.CreateOrUpdateRole(role); err != nil {
		return err
	}

	// Set the ID
	d.SetId(name)

	return nil
}

