def load_yaml(filename, quiet=False, enforce_exists=True):
    """
    Load a YAML file and return its contents.

    If enforce_exists is True, raise a IOError if the file does not exist.
    If quiet is True, don't print warnings if the file does not exist.
    """
    if enforce_exists and not os.path.exists(filename):
        e = IOError("File not found: %s" % filename)
        if not quiet:
            logger.warning("", exc_info=e)
        raise e
    try:
        with open(filename, "r") as f:
            contents = yaml.load(f)
    except yaml.YAMLError as e:
        if not quiet:
            logger.warning("", exc_info=e)
        raise CLILoadError(e)
    return contents

