def test_tags_are_valid(self):
    """Test that the tags we're using on the feature are valid."""
    feature = self.get_feature_by_name(self.feature_name)
    tags = feature.get("tags", [])

    # Check the version tags are present
    for tag in ["bpo-" + self.bug.id, "version-" + self.version.version] + self.version.get_tags():
        self.assertIn(tag, tags, "Missing tag %s on feature %s" % (tag, self.feature_name))

    # Check the bugzilla tags are present
    for tag in self.bug.tags:
        self.assertIn(tag, tags, "Missing tag %s on feature %s" % (tag, self.feature_name))

    # Check the tag registry is valid
    for tag in tags:
        if tag.startswith("feature-"):
            self.assertIn(
                tag[len("feature-") :],
                [name for (name, data) in self.registry.items() if self.bug.id in data["bugs"]],
                "Unknown feature tag %s on feature %s" % (tag, self.feature_name),
            )

