def load(self, filename):
    """
    Load data from a file.

    The file type is determined by the file extension.

    ============== ===============================================================
    File type      Description
    ============== ===============================================================
    `.csv`         Comma separated values.
    `.tsv`         Tab separated values.
    `.xls`, `.xlsx` Excel spreadsheet.
    `.sas7bdat`    SAS data file.
    `.pickle`      Python pickle.
    ============== ===============================================================

    Parameters
    ----------
    filename : str
        File name.

    """

    # Check the file extension to determine the loader function.
    filename = os.path.abspath(filename)
    name, ext = os.path.splitext(filename)
    if ext == '.csv':
        return self.load_csv(filename)
    elif ext == '.tsv':
        return self.load_csv(filename, sep='\t')
    elif ext == '.xls' or ext == '.xlsx':
        return self.load_excel(filename)
    elif ext == '.sas7bdat':
        return self.load_sas(filename)
    elif ext == '.pickle':
        return self.load_pickle(filename)
    else:
        raise ValueError("Cannot load data from files with extension %s" % ext)

