def update_shared_config(shared_config, exporter_configs):
    """
    Updates a shared configuration (dict) with exporter details from multiple YAML files.
    :param shared_config: The shared configuration dict to update.
    :param exporter_configs: A list of YAML file paths containing exporter details.
    """
    for e_config in exporter_configs:
        logging.info("Loading exporter definitions from %s", e_config)
        with open(e_config, 'r') as yaml_file:
