def get_surface_brightness(self, star, band, cache=True):
    """
    Calculate and return the surface brightness of a star in a given band.

    If `cache` is true, the value will be cached for later use.
    """
    if not hasattr(star, 'mag'):
        star.calculate_mags()
    if not hasattr(star, 'sb'):
        star.sb = {}
    if band not in star.sb or not cache:
        if hasattr(star, 'ep'):
            ep = star.ep[band]
        else:
            ep = self.get_ep(star.id, band)
        if ep == 0:
            sb = 0
        else:
            sb = -2.5 / np.log10(ep)
        if cache:
            star.sb[band] = sb
    return star.sb[band]

