def set_pre_prov_vars(vm_id, prov_type)
    @vm_id = vm_id
    @prov_type = prov_type
    @report_id = nil
    @report_hash = nil

    if prov_type == "vm"
      @record = Vm.find_by_id(@vm_id)
    else
      @record = MiqTemplate.find_by_id(@vm_id)
    end

    @vm_name = @record.name

    # Get the last REPORT record for this VM
    reports = MiqReportResult.where(:resource_id => @vm_id, :resource_type => prov_type)
    reports.each { |r| @report_id = r.id if r.end_time > Time.now.utc - 1.minute }
    raise _("No active report found for this VM") if @report_id.nil?

    @report_hash = MiqReportResult.find(@report_id).results
    @config = YAML.load(@record.provisioning_config)
  end

