func (s *Server) serveLanding(w http.ResponseWriter, r *http.Request) {
	id := r.URL.Path[len("/l/"):]

	// Decode the id.
	decoded, err := url.QueryUnescape(id)
	if err != nil {
		http.Error(w, "invalid path", http.StatusBadRequest)
		return
	}

	// Find the path for this id.
	s.mu.RLock()
	path, ok := s.paths[decoded]
	s.mu.RUnlock()

	// If no path was found, this id was not created via aph.
	if !ok {
		http.Error(w, "not found", http.StatusNotFound)
		return
	}

	// Append the fragment.
	full := path.Path + "#" + path.Fragment

	// Write the response.
	w.Header().Set("Content-Type", "text/html; charset=utf8")
	w.Header().Set("Content-Length", fmt.Sprint(len(landingPage)))
	w.WriteHeader(http.StatusOK)
	fmt.Fprint(w, landingPage, full)
}

