func (s *basketServer) serveCreate(w http.ResponseWriter, r *http.Request) {
	var req createBasketRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		s.logger.Printf("could not decode create basket request: %s", err)
		http.Error(w, "could not decode request", http.StatusBadRequest)
		return
	}
	if req.Name == "" {
		http.Error(w, "name must not be empty", http.StatusBadRequest)
		return
	}
	if !s.isValidName(req.Name) {
		http.Error(w, "invalid name", http.StatusBadRequest)
		return
	}
	if req.ForwardURL != "" && !s.isValidForwardURL(req.ForwardURL) {
		http.Error(w, "invalid ForwardURL", http.StatusBadRequest)
		return
	}

	b := &basket{
		Name:        req.Name,
		ForwardURL:  req.ForwardURL,
		CreatedTime: time.Now(),
		UpdatedTime: time.Now(),
	}
	if err := s.store.CreateBasket(r.Context(), b); err != nil {
		s.logger.Printf("could not create basket: %s", err)
		http.Error(w, "could not create basket", http.StatusInternalServerError)
		return
	}
	s.notifyNewBasket(b)
	json.NewEncoder(w).Encode(createBasketResponse{BasketID: b.ID})
}

