protected void doGet(HttpServletRequest request, HttpServletResponse response)
      throws ServletException, IOException {

    // Set the response's content type.
    response.setContentType("text/html;charset=UTF-8");

    // Allocate a output writer to render the response into.
    PrintWriter out = response.getWriter();

    // Create a session if there is no one currently.
    HttpSession session = request.getSession(true);

    // Get the user stored in the session.
    Object user = session.getAttribute("user");

    // If there is no user stored in the session, then
    // redirect the user to the login page.
    if (user == null) {
      response.sendRedirect(getServletContext().getAttribute("login").toString());
      return;
    }

    // Cast the user object into a User object.
    User theUser = (User) user;

    // Get the parameters from the request.
    String action = request.getParameter("action");
    String projectName = request.getParameter("project");
    String branch = request.getParameter("branch");
    String hash = request.getParameter("hash");
    String path = request.getParameter("path");
    String toHash = request.getParameter("toHash");
    String toPath = request.getParameter("toPath");

    // If the parameters are empty, then redirect the user to the
    // parent page.
    if (action == null || projectName == null || branch == null ||
        hash == null || path == null) {
      response.sendRedirect("code.html");
      return;
    }

    // Create the parameters for the JSP.
    Map<String, Object> params = new HashMap<String, Object>();
    params.put("action", action);
    params.put("project", projectName);
    params.put("branch", branch);
    params.put("hash", hash);
    params.put("path", path);
    params.put("toHash", toHash);
    params.put("toPath", toPath);
    params.put("user", theUser);

    // If the user is not allowed to access the requested code, then
    // redirect the user to the parent page.
    if (!CodeServlet.canAccessCode(projectName, branch, hash, path, theUser)) {
      response.sendRedirect("code.html");
      return;
    }

    // If the user is trying to view a directory, then redirect them
    // to the corresponding code.html page.
    if (path.endsWith("/")) {
      response.sendRedirect("code.html?" +
                            "project=" + projectName + "&" +
                            "branch=" + branch + "&" +
                            "hash=" + hash + "&" +
                            "path=" + path.substring(0, path.length()-1));
      return;
    }

    // If the user is trying to view a file, then render the
    // appropriate JSP.
    else {

      // If the user is trying to view a patch, then retrieve the
      // patch information and render the _code_patch JSP.
      if (path.endsWith(".patch")) {
        PatchSet patchSet = null;
        try {
          patchSet = CodeServlet.getPatchSet(projectName, branch, hash);
        } catch (PatchSetNotFoundException e) {
          e.printStackTrace();
          response.sendError(
              HttpServletResponse.SC_INTERNAL_SERVER_ERROR,
              "Cannot find patch set " + hash + " for " + projectName +
              " on " + branch);
          return;
        }

        int patchNum = -1;
        for (PatchSetEntry entry : patchSet.getPatches()) {
          if (entry.getNewFile().getPath().equals(path)) {
            patchNum = entry.getPatchNum();
            break;
          }
        }

        if (patchNum == -1) {
          response.sendError(
              HttpServletResponse.SC_NOT_FOUND,
              "File not found: " + path);
          return;
        }

        params.put("patchNum", patchNum);
        render("_code_patch.jsp", params, request, response, out);
      }

      // If the user is trying to view a file, then render the
      // _code_file JSP.
      else {
        render("_code_file.jsp", params, request, response, out);
      }
    }
  }

