public void showErrorPage(HttpServletRequest request, Writer writer,
                          Throwable t) throws IOException {

    // If an invoke target was specified, then use it
    Object et = request.getAttribute("javax.servlet.error.exception");
    if (et != null) {
        t = (Throwable) et;
    }

    // Generate a stack trace for this exception
    String stackTrace = getStackTrace(t);

    // Save this information in the request so that it can be displayed
    // on the error page.
    request.setAttribute("javax.servlet.error.status_code", "500");
    request.setAttribute("javax.servlet.error.message", t.getMessage());
    request.setAttribute("javax.servlet.error.exception", t);
    request.setAttribute("javax.servlet.error.stack_trace", stackTrace);

    // Forward to the error page
    getServletContext().getRequestDispatcher(getErrorPage()).forward(request, writer);

}

