function replaceElementWithForm(e) {
  var el = e.target;
  var form = document.createElement("form");
  form.setAttribute("method", "post");
  form.setAttribute("action", "/_edit");
  var input = document.createElement("input");
  input.setAttribute("type", "hidden");
  input.setAttribute("name", "csrfmiddlewaretoken");
  input.value = getCookie('csrftoken');
  form.appendChild(input);
  input = document.createElement("input");
  input.setAttribute("type", "hidden");
  input.setAttribute("name", "path");
  input.value = el.getAttribute("data-path");
  form.appendChild(input);
  input = document.createElement("input");
  input.setAttribute("type", "hidden");
  input.setAttribute("name", "lineno");
  input.value = el.getAttribute("data-lineno");
  form.appendChild(input);
  input = document.createElement("textarea");
  input.setAttribute("name", "content");
  input.style.width = "100%";
  input.style.height = "100%";
  input.value = el.textContent;
  form.appendChild(input);
  var button = document.createElement("input");
  button.setAttribute("type", "submit");
  button.style.margin = "10px";
  button.style.padding = "10px";
  button.style.backgroundColor = "#e5e5e5";
  button.style.border = "1px solid #cccccc";
  button.style.borderRadius = "5px";
  button.style.cursor = "pointer";
  button.appendChild(document.createTextNode("Save"));
  form.appendChild(button);
  el.parentNode.insertBefore(form, el);
  el.parentNode.removeChild(el);
}

