          user.style.display = 'none';
        }
      }
    }

    function setUser(value) {
      if (user != value) {
        user = value;
        if (user) {
          userName.innerHTML = user.username;
          userNameYou.innerHTML = user.username;
          userImagePlaceholder.style.backgroundImage = 'url(' + user.image + ')';
          userImagePlaceholder.style.backgroundSize = 'cover';
        } else {
          userName.innerHTML = '';
          userNameYou.innerHTML = 'you';
          userImagePlaceholder.style.backgroundImage = '';
        }
      }
    }

    function doSearch() {
      var params = getHashParams();
      var url = '/api/search/';
      if (params.q)
        url += params.q;
      else
        return;
      if (params.hasOwnProperty('p'))
        url += '?p=' + params.p;
      else if (params.hasOwnProperty('sort'))
        url += '?sort=' + params.sort + '&desc=' + params.desc;
      else if (params.hasOwnProperty('show'))
        url += '?show=' + params.show;
      else
        return;
      loading.style.display = 'block';
      noStories.style.display = 'none';
      stories.innerHTML = '';
      httpGet(url, function(storiesData) {
        loading.style.display = 'none';
        if (storiesData.error) {
          noStories.style.display = 'block';
          noStories.innerHTML = storiesData.error;
        } else {
          var storiesHtml = '';
          for (var i = 0; i < storiesData.stories.length; i++) {
            var storyData = storiesData.stories[i];
            var storyHtml = storyTemplate.innerHTML;
            storyHtml = storyHtml.replace(/\$TITLE\$/g, storyData.title);
            storyHtml = storyHtml.replace(/\$URL\$/g, storyData.url);
            storyHtml = storyHtml.replace(/\$AUTHOR\$/g, storyData.author);
            storyHtml = storyHtml.replace(/\$AGE\$/g, storyData.age);
            storyHtml = storyHtml.replace(/\$SCORE\$/g, storyData.score);
            storyHtml = storyHtml.replace(/\$CONTENT\$/g, storyData.content);
            storyHtml = storyHtml.replace(/\$MEDIA\$/g, storyData.media);
            storyHtml = storyHtml.replace(/\$COMMENTS\$/g, storyData.comments);
            storiesHtml += storyHtml;
          }
          stories.innerHTML = storiesHtml;
          for (var i = 0; i < storiesData.stories.length; i++) {
            var storyData = storiesData.stories[i];
            var story = document.getElementById('s' + storyData.id);
            if (storyData.url == '') {
              story.className += ' nourl';
            } else {
              story.className += ' url';
            }
            if (storyData.content)
              story.className += ' hascontent';
            if (storyData.media)
              story.className += ' hasmedia';
            if (storyData.comments)
              story.className += ' hascomments';
          }
          var pages = document.createElement('div');
          pages.className = 'pages';
          stories.appendChild(pages);
          var pagesText = document.createElement('span');
          pagesText.className = 'text';
          pages.appendChild(pagesText);
          var pagesBack = document.createElement('a');
          pagesBack.className = 'back';
          pages.appendChild(pagesBack);
          var pagesForward = document.createElement('a');
          pagesForward.className = 'forward';
          pages.appendChild(pagesForward);
          if (params.p) {
            var p = parseInt(params.p.substr(1));
            if (p > 1) {
              pagesBack.href = '/_h/' + (p - 1);
            } else {
              pagesBack.style.display = 'none';
            }
            if (p < storiesData.pages) {
              pagesForward.href = '/_h/' + (p + 1);
            } else {
              pagesForward.style.display = 'none';
            }
          } else {
            pagesBack.style.display = 'none';
            pagesForward.style.display = 'none';
          }
        }
      });
    }

    function doNotificationInd() {
      var params = getHashParams();
      var url = '/api/notifications/ind';
      httpGet(url, function(notificationsData) {
        if (notificationsData.error) {
          alert(notificationsData.error);
