          setNotifications(notificationsData.notifications);
        }
      });
    }

    function doMessageInd() {
      var params = getHashParams();
      var url = '/api/message/ind';
      httpGet(url, function(messagesData) {
        if (messagesData.error) {
          alert(messagesData.error);
        } else {
          setMessages(messagesData.messages);
        }
      });
    }

    function doSavedInd() {
      var params = getHashParams();
      var url = '/api/saved/ind';
      httpGet(url, function(savedData) {
        if (savedData.error) {
          alert(savedData.error);
        } else {
          setSaved(savedData.saved);
        }
      });
    }

    function doUserInd() {
      var params = getHashParams();
      var url = '/api/user/ind';
      httpGet(url, function(userData) {
        if (userData.error) {
          alert(userData.error);
        } else {
          setLoggedIn(true);
          setUser(userData.user);
        }
      });
    }

    function setNotifications(notifications) {
      var unread = 0;
      for (var i = 0; i < notifications.length; i++) {
        if (!notifications[i].read)
          unread++;
      }
      if (unread) {
        userNotifications.innerHTML = 'notifications (' + unread + ')';
      } else {
        userNotifications.innerHTML = 'notifications';
      }
    }

    function setMessages(messages) {
      var unread = 0;
      for (var i = 0; i < messages.length; i++) {
        if (!messages[i].read)
          unread++;
      }
      if (unread) {
        userMessages.innerHTML = 'messages (' + unread + ')';
      } else {
        userMessages.innerHTML = 'messages';
      }
    }

    function setSaved(saved) {
      var unread = 0;
      for (var i = 0; i < saved.length; i++) {
        if (!saved[i].read)
          unread++;
      }
      if (unread) {
        userSaved.innerHTML = 'saved (' + unread + ')';
      } else {
        userSaved.innerHTML = 'saved';
      }
    }

    function httpGet(url, cb) {
      var r = new XMLHttpRequest();
      r.open("GET", url, true);
      r.onreadystatechange = function() {
        if (r.readyState != 4)
          return;
        var data = null;
        try {
          data = JSON.parse(r.responseText);
        } catch (e) {
          data = {error: "Invalid JSON: " + r.responseText};
        }
        cb(data);
      };
      r.send(null);
    }

    function getHashParams() {
      var match,
          pl = /\+/g,  // Regex for replacing addition symbol with a space
          search = /([^&=]+)=?([^&]*)/g,
          decode = function (s) { return decodeURIComponent(s.replace(pl, " ")); },
          query = window.location.hash.substring(1).match(search),
          params = {};
      while (match = search.exec(window.location.hash.substring(1)))
        params[decode(match[1])] = decode(match[2]);
      return params;
    }

