function updateDataEntry(table, record, column, value) {
    var data = table.getData();
    var entry = data.getEntry(record);
    var field = entry.getField(column);
    if (field.isImageBased()) {
        var image = value;
        if (image) {
            image = image.src;
        }
        entry.setImage(column, image);
    } else {
        entry.setField(column, value);
    }
    data.setEntry(record, entry);
    table.draw();
}

