searchAll(input) {
  var params = input.split('=');
  var field = params[0];
  var text = params[1];

  // Update URL
  var url = window.location.href;
  var re = new RegExp('([&\\?])' + field + '=.*?(&|#|$)', '');
  if (url.search(re) >= 0) {
    url = url.replace(re, '$1' + field + '=' + text + '$2');
  } else {
    if (url.indexOf('?') < 0) {
      url += '?';
    } else {
      url += '&';
    }
    url += field + '=' + text;
  }
  history.pushState(null, '', url);

  // Perform search
  search(field, text, true);
}

