    if (c.settings.readOnly) {
      c.setReadOnly(true);
    }

    // initialize content
    c.setContent(c.settings.content, false);

    // initialize visibility
    if (c.settings.visible) {
      c.show();
    } else {
      c.hide();
    }

    // initialize style
    if (c.settings.style) {
      c.setStyle(c.settings.style);
