$(document).on('change', '[data-behavior="modal-submit-handler"]', function(event) {
  var $form = $(this),
      $modal = $form.closest('.modal'),
      $target = $($form.data('target'));

  // If the checkbox is "inverted", i.e. appears checked when unchecked and vice versa,
  // then it needs to be handled differently in the serialized data
  if ($form.data('serialized-invert')) {
    var serialized = $form.serializeArray();

    serialized.forEach(function(el) {
      if (el.name === 'invert') {
        el.value = !el.value;
      }
    });

    return $target.trigger('submit', [ serialized ]);
  }

  $target.trigger('submit', [ $form.serialize() ]);
  $modal.modal('hide');

  return false;
});

