function searchCallback(data) {
  var results = data.response.results;
  var noResultsElement = document.getElementById('search-no-results');

  if (results.length) {
    var template = document.getElementById('search-result-template').content;
    var container = document.getElementById('search-results-container');
    container.innerHTML = '';
    results.forEach(function(result) {
      var clone = template.cloneNode(true);
      var el;
      el = clone.querySelector('a[data-search-result-url]');
      el.href = result.url;
      el.text = result.title;
      el = clone.querySelector('[data-search-result-title]');
      el.textContent = result.title;
      el = clone.querySelector('[data-search-result-url]');
      el.textContent = result.url;
      container.appendChild(clone);
    });
  } else {
    noResultsElement.classList.remove('hidden');
  }
}

