static void im_append_message(ImWidget *im, MessageInfo *msg)
{
    bool self_msg = (im->info->id == msg->from_id);
    GString *str = g_string_new("");
    char *mention_str = NULL;

    if (msg->type == MESSAGE_INFO_TYPE_CHAT) {
        if (self_msg)
            g_string_append(str, "<i>");

        mention_str = get_user_mention(im, msg->from_id);
        if (mention_str) {
            g_string_append(str, mention_str);
            g_string_append(str, ": ");
            g_free(mention_str);
        }

        if (msg->media)
            g_string_append(str, msg->media);
        else
            g_string_append(str, msg->text);

        if (!self_msg)
            g_string_append(str, "<i>");
    } else if (msg->type == MESSAGE_INFO_TYPE_NOTE) {
        g_string_append(str, "/me ");
        g_string_append(str, msg->text);
    } else if (msg->type == MESSAGE_INFO_TYPE_JOIN)
        g_string_append(str, "<b>* Eintrag hinzugefügt</b>");
    else if (msg->type == MESSAGE_INFO_TYPE_LEAVE)
        g_string_append(str, "<b>* Eintrag entfernt</b>");
    else if (msg->type == MESSAGE_INFO_TYPE_TOPIC) {
        g_string_append(str, "<b>* Thema geändert:</b> ");
        g_string_append(str, msg->text);
    } else if (msg->type == MESSAGE_INFO_TYPE_KICK) {
        mention_str = get_user_mention(im, msg->from_id);
        g_string_append(str, "<b>* ");
        if (mention_str) {
            g_string_append(str, mention_str);
            g_string_append(str, " hat ");
            g_free(mention_str);
        }
        g_string_append(str, msg->text);
        g_string_append(str, " entfernt</b>");
    } else if (msg->type == MESSAGE_INFO_TYPE_QUOTE) {
        g_string_append(str, "<i>");
        g_string_append(str, msg->text);
        g_string_append(str, "</i>");
    }

    gtk_list_box_append(GTK_LIST_BOX(im->chat_view),
            tny_simple_list_item_new_with_subtitle(msg->from_name, str->str));
    g_string_free(str, TRUE);

    if (self_msg) {
        str = g_string_new("");
        g_string_append(str, msg->from_name);
        g_string_append(str, ": ");
        if (msg->media)
            g_string_append(str, msg->media);
        else
            g_string_append(str, msg->text);
        im_append_self_message(im, str->str);
        g_string_free(str, TRUE);
    }

    tny_list_view_scroll_to_location(TNY_LIST_VIEW(im->chat_view),
            GTK_LIST_BOX(im->chat_view),
            gtk_list_box_get_row_at_y(GTK_LIST_BOX(im->chat_view), -1),
            FALSE, 0, 0);
}

