function updateRegExp()
    {
        var re = document.getElementById("regexp");
        var validation = document.getElementById("validation");
        var source = document.getElementById("source");

        re.pattern = escapeRegExp(re.value);
        validation.innerHTML = "<span class=\"pass\">This regexp is valid.</span>";

        var flags = getFlags();
        var sticky = (flags.indexOf("y") != -1);
        var multiline = (flags.indexOf("m") != -1);
        source.value =
            (sticky ? "/sticky " : "") +
            (multiline ? "/multiline " : "") +
            ("//" + flags) +
            "(\n" +
             "  document.getElementById('regexp').value\n" +
             ")";
    }

