Alert.$inject = ['$modal'];

function Alert($modal) {
    var Alert = {
        show: show
    };

    return Alert;

    ///////////////

    function show(options) {
        var defaults = {
            title: 'Attention',
            message: '',
            type: 'warning',
            showInput: false,
            inputLabel: '',
            inputPlaceholder: '',
            inputType: 'text',
            inputValue: '',
            showCancelButton: false,
            cancelButtonText: 'Cancel',
            showConfirmButton: true,
            confirmButtonText: 'OK',
            confirmButtonType: 'primary',
            closeOnConfirm: true,
            closeOnCancel: true,
            showLoaderOnConfirm: false,
            html: false,
            timer: null,
            animation: true,
            customClass: ''
        };
        var userOptions = angular.copy(options);
        userOptions.inputValue = userOptions.inputValue || '';

        var mergedOptions = angular.merge(defaults, userOptions);

        var ModalInstance = $modal.open({
            templateUrl: 'alert.html',
            controller: 'AlertController',
            backdrop: 'static',
            keyboard: false,
            animation: mergedOptions.animation,
            resolve: {
                options: function() {
                    return mergedOptions;
                }
            }
        });

        ModalInstance.result.then(function(buttonPressed) {
            if (buttonPressed === 'ok') {
                if (angular.isDefined(userOptions.onConfirm) &&
                    angular.isFunction(userOptions.onConfirm)) {
                    userOptions.onConfirm(userOptions.inputValue);
                }
            } else if (buttonPressed === 'cancel') {
                if (angular.isDefined(userOptions.onCancel) &&
                    angular.isFunction(userOptions.onCancel)) {
                    userOptions.onCancel(userOptions.inputValue);
                }
            }
        });
    }
}

