      $optionField.val('');
      $previewText.text('(None)');
    }
    else if (selectedType === 'radio' || selectedType === 'checkbox') {
      var optionCount = $optionRow.find('.option-field').length;
      if (optionCount === 0) {
        $optionField.val('');
        $previewText.text('(None)');
      }
      else {
        var selectedOptions = [];
        $optionRow.find('.option-field:checked').each(function(i) {
          selectedOptions.push($(this).val());
        });
        if (selectedOptions.length === 0) {
          $previewText.text('(None)');
        }
        else if (selectedOptions.length === 1) {
          $previewText.text(selectedOptions[0]);
        }
        else {
          $previewText.text(selectedOptions[0] + ' + ' + (selectedOptions.length - 1) + ' more');
        }
      }
    }
    else if (selectedType === 'scale') {
      var minValue = $optionRow.find('.scale-min').val();
      var maxValue = $optionRow.find('.scale-max').val();
      $optionField.val(minValue + '..' + maxValue);
      $previewText.text('(None)');
    }
    else if (selectedType === 'date') {
      $optionField.val('');
      $previewText.text('(None)');
    }
  });

