@app.route('/variables/<path:filename>', methods=['GET', 'POST'])
def handle_variable(filename):
    if request.method == 'GET':
        return http_util.generate_response(
            request,
            http_util.Responses.OK,
            body=open(os.path.join(app.config['UPLOAD_FOLDER'], filename)).read())
    if request.method == 'POST':
        if 'file' not in request.files:
            return http_util.generate_response(
                request, http_util.Responses.BAD_REQUEST)
        f = request.files['file']
        if f.filename == '':
            return http_util.generate_response(
                request, http_util.Responses.BAD_REQUEST)
        filename = secure_filename(f.filename)
        f.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
        return http_util.generate_response(request, http_util.Responses.CREATED)

