def debug_log(self, args):
    """
    Usage: debug_log [ -f filename ] [ user ]

    -f filename   Display log file named filename
    user         Display log file for named user
    """

    filename = None
    if len(args) == 2:
        if args[1] == '--help':
            self.help('debug_log')
            return
        filename = args[1]
    elif len(args) == 3:
        filename = '/var/log/maillog'
    if not filename:
        self.error("You must provide a filename")

    if not os.path.exists(filename):
        self.error("File %s does not eist" % filename)

    try:
        f = open(filename)
    except:
        self.error("Can't open %s" % filename)

    user = None
    if len(args) == 3:
        user = args[2]

    def display(line):
        if user:
            if line.find(user) == -1:
                return
        self.stdout.write(line)

    for line in f.readlines():
        if line.find('[') == -1:
            continue
        line = line.rstrip()
        if line.find(': ') == -1:
            continue
        t, line = line.split(': ', 1)
        t = t.strip()
        if t == 'admin':
            continue
        if user and t != user:
            continue
        display(line)

