        if 'delete' in post_vars:
            vars['mode'] = 'delete'
            vars['id'] = post_vars['id']
        elif 'edit' in post_vars:
            vars['mode'] = 'edit'
            vars['id'] = post_vars['id']
        elif 'show' in post_vars:
            vars['mode'] = 'show'
