        elif 'create' in post_vars:
            vars['mode'] = 'create'
        return vars

    vars = {}
    vars.update(csrf_token(request))
    vars['title'] = _('Variables')
    vars['mode'] = 'list'

    post_vars = request.post_vars
    if post_vars:
        vars = postprocess(vars, vars, post_vars)

    get_vars = request.get_vars
    if get_vars:
        vars = postprocess(vars, vars, get_vars)

    if 'mode' in vars:
        if vars['mode'] == 'delete':
            db(db.t_variable.id == vars['id']).delete()
            action_log.write(request, _("Variable deleted"), "variable")
            response.flash = _("Variable deleted")
        elif vars['mode'] == 'edit':
            vars['variable'] = db.t_variable[vars['id']]
            if 'update' in post_vars:
                db(db.t_variable.id == vars['id']).update(
                    key=post_vars['key'],
                    value=post_vars['value'],
                    user_id=auth.user_id,
                    )
                action_log.write(request, _("Variable updated"), "variable")
                response.flash = _("Variable updated")
            elif 'cancel' in post_vars:
                vars['mode'] = 'show'
        elif vars['mode'] == 'create':
            if 'create' in post_vars:
                db.t_variable.insert(
                    key=post_vars['key'],
                    value=post_vars['value'],
                    user_id=auth.user_id,
                    )
                action_log.write(request, _("Variable created"), "variable")
                response.flash = _("Variable created")
                vars['mode'] = 'list'
        elif vars['mode'] == 'show':
            vars['variable'] = db.t_variable[vars['id']]

    if not 'variable' in vars:
        vars['variable'] = {}

    vars['variable_list'] = db(db.t_variable).select()
    return auth.view_factory(module='admin', component='variable')(**vars)

