def post(self):
    """
    Create a new user account or reactivate a disabled one.

    The request can include the following keys:

    * username: the new username (required)
    * password: the new password (required)
    * email: the email address (required)
    * admin: set to true to grant admin privileges (optional)
    * active: set to false to create a disabled account (optional)

    On a successful creation or reactivation, the ID of the account is
    returned.  Otherwise an error message is returned.
    """
    self.check_admin()
    data = self.get_json()

    username = data.get('username')
    if not username:
        return self.error('Missing username')
    if not is_valid_username(username):
        return self.error('Invalid username')

    with self.store.begin(write=True) as txn:
        if txn.get_user_by_username(username):
            return self.error('Duplicate username')

        password = data.get('password')
        if not password:
            return self.error('Missing password')
        if len(password) > 2048:
            return self.error('Password is too long')

        email = data.get('email')
        if not email:
            return self.error('Missing email')
        if not is_valid_email(email):
            return self.error('Invalid email')

        admin = data.get('admin', False)
        if admin and not self.store.allow_admin_registration:
            return self.error('Admin registration is disabled',
                               status_code=400)

        active = data.get('active', True)

        user = User(username, password, email, admin=admin, active=active)
        txn.add(user)
        txn.commit()

    return self.json(user.id)

