function (callback) {
  var command = 'lsblk -P -b -o KNAME,PKNAME,TYPE,SIZE,RO,MOUNTPOINT';

  if (this.opts.ignore_devices) {
    command += ' ' + this.opts.ignore_devices.join(' ');
  }

  if (this.opts.ignore_majors) {
    command += ' --ignore=' + this.opts.ignore_majors.join(',');
  }

  this.debug(command);
  this.exec(command, function (err, stdout) {
    if (err) {
      return callback(err);
    }

    var devices = [];
    var rows = stdout.split('\n');

    rows.forEach(function (row) {
      var columns = row.split(' ');

      if (columns.length < 5) {
        return;
      }

      var device = {
        name: columns[0],
        parent: columns[1],
        type: columns[2],
        size: parseInt(columns[3], 10),
        ro: columns[4] === '1',
        mountpoint: columns[5]
      };

      devices.push(device);
    });

    callback(null, devices);
  });
}

