def _manage_git_repo(self, name, create=False, revision=None,
                     submodules=False, update=False, bare=False,
                     short_reference=False, env=None, git_url=None,
                     reference=None, relpath=None, version='master'):
    """
    Helper function to manage a git repository by creating or updating it and
    setting file permissions.
    """
    if create:
        self.run('git init {name}'.format(name=name))
        if bare:
            self.run('git --git-dir={name}/.git config --bool core.bare true'
                     .format(name=name))
        for d in ('hooks', 'info', 'objects', 'refs', 'remotes'):
            self.mkdir('{name}/{d}'.format(name=name, d=d))
        self.mkdir('{name}/.git'.format(name=name))
        self.write_file('{name}/HEAD'.format(name=name),
                        'ref: refs/heads/master\n')

    if git_url:
        self.run('git remote add origin {url}'.format(url=git_url))

    if update:
        if submodules:
            self.run('git submodule update --init --recursive')
        self.run('git fetch origin {version}'.format(version=version))
        if revision:
            self.run('git reset --hard {revision}'.format(revision=revision))
        else:
            self.run('git reset --hard FETCH_HEAD')
    elif revision:
        self.run('git checkout {revision}'.format(revision=revision))
    else:
        self.run('git checkout {name}'.format(name=version))
    self.run('git submodule update --init --recursive')

