def get_youtube_title(url):
    """
    Returns the title of a YouTube video given its URL.
    """
    args = ["youtube-dl", "--get-title", url]
    try:
        title = subprocess.check_output(args).decode("utf-8").strip()
    except subprocess.CalledProcessError:
        title = None
    return title

