func getRecord(w http.ResponseWriter, r *http.Request) {
	// Get the ID from the URL wildcard
	keys, ok := mux.Vars(r)["id"]
	if !ok {
		http.Error(w, "Not found", http.StatusNotFound)
		return
	}

	// Convert the string into an integer
	id, err := strconv.Atoi(keys)
	if err != nil {
		http.Error(w, "Not found", http.StatusNotFound)
		return
	}

	// Get a connection to the database
	db, err := getDB()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer db.Close()

	// Define the SQL statement to get a record
	var sqlStatement = "SELECT * FROM test WHERE id = ?"

	// Prepare the SQL statement
	stmt, err := db.Prepare(sqlStatement)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	// Get the record
	var result Record
	err = stmt.QueryRow(id).Scan(&result.ID, &result.Name, &result.Email, &result.Phone)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	// Display the record
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(result)
}

func displayTable(w http.ResponseWriter, r *http.Request) {
	_, err := checkCookie(w, r)
	if err != nil {
		http.Redirect(w, r, "/login/", http.StatusFound)
		return
	}

	table := r.FormValue("table")
	if table == "" {
		http.Error(w, "Missing table parameter", http.StatusBadRequest)
		return
	}

	db, err := sql.Open("mysql", dsn)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer db.Close()

	rows, err := db.Query("SELECT * FROM " + table)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	cols, err := rows.Columns()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	ct := make([]interface{}, len(cols))
	cv := make([]interface{}, len(cols))
	for i := range ct {
		ct[i] = &cv[i]
	}

	type row struct {
		Values []string
	}
	var rowsOut []row

	for rows.Next() {
		if err := rows.Scan(ct...); err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		var values []string
		for _, v := range cv {
			values = append(values, fmt.Sprintf("%v", v))
		}
		rowsOut = append(rowsOut, row{Values: values})
	}
	if err := rows.Err(); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	data := struct {
		TableName string
		Cols      []string
		Rows      []row
	}{table, cols, rowsOut}

	if err := templates.ExecuteTemplate(w, "displaytable", data); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
}

DisplayRecords(w http.ResponseWriter, r *http.Request) {
	// Initialize a session and recycle old one
	session := SessionInit(w, r)

	// Check if user is logged in
	if !session.IsLogged() {
		http.Redirect(w, r, "/", http.StatusSeeOther)
		return
	}

	// Get the name of the table to show from the URL path
	split := strings.Split(r.URL.Path, "/")
	table := split[len(split)-1]

	// Check if the table exists
	if !DB.TableExists(table) {
		session.AddFlash(w, r, FormError, "Table does not exist")
		http.Redirect(w, r, "/", http.StatusSeeOther)
		return
	}

	// Get the records from the table
	records, err := DB.GetRecords(table)
	if err != nil {
		session.AddFlash(w, r, FormError, "Unable to get records")
		log.Println(err.Error())
		http.Redirect(w, r, "/", http.StatusSeeOther)
		return
	}

	// Show the records in the template
	err = TEMPLATES.ExecuteTemplate(w, "records", Records{Records: records, Title: table})
	if err != nil {
		session.AddFlash(w, r, FormError, "Unable to display records")
		log.Println(err.Error())
	}
}

