def user_login(request):
    """
    User login view.

    Renders different templates based on the HTTP method.
    """
    if request.method == 'GET':
        return render(request, 'login.html')
    elif request.method == 'POST':

        # Check if user has provided credentials.
        if 'username' and 'password' in request.POST:
            username = request.POST['username']
            password = request.POST['password']

            # Check user credentials and log the user in.
            user = authenticate(username=username, password=password)
            if user is not None and user.is_active:
                login(request, user)
                # Return a redirect after successful login.
                return redirect('home')

        # If we get here then the credentials were invalid.
        return render(request, 'login.html', {'invalid_login': True})

