    private final Map<String, File> nbmCache = new HashMap<String, File>();

    public ModuleManager(File cache) {
        this.cache = cache;
    }

    public void clearCache() {
        infoCache.clear();
        nbmCache.clear();
    }

    public ModuleInfo getInfo(File file) throws IOException {
        String url = file.toURI().toURL().toString();
        return getInfo(url);
    }

    public ModuleInfo getInfo(String url) throws IOException {
        ModuleInfo info = infoCache.get(url);
        if (info == null) {
            File dir = cache.getCanonicalFile();
            info = ModuleInfo.read(url, dir);
            infoCache.put(url, info);
        }
        return info;
    }

    public File getNBM(File file) throws IOException {
        String url = file.toURI().toURL().toString();
        return getNBM(url);
    }

    public File getNBM(String url) throws IOException {
        File nbm = nbmCache.get(url);
        if (nbm == null) {
            nbm = createNBM(url);
            nbmCache.put(url, nbm);
        }
        return nbm;
    }

    private File createNBM(String url) throws IOException {
        File dir = cache;
        if (!dir.exists() && !dir.mkdirs()) {
            throw new IOException("Cannot create directory " + dir); // NOI18N
        }
        String name = Utilities.getURLFileName(url);
        File file = new File(dir, name);
        if (file.isDirectory()) {
            file = new File(dir, name + NB_MODULE_SUFFIX);
        }
        if (!file.exists()) {
            File tmp = File.createTempFile(name, NB_MODULE_SUFFIX, dir);
            Utilities.copy(url, tmp);
            if (!tmp.renameTo(file)) {
                throw new IOException("Cannot rename " + tmp + " to " + file); // NOI18N
            }
        }
        return file;
    }
}

