                        }
                    }
                    tarEntry = tarIn.getNextTarEntry();
                }
            } finally {
                IOUtils.closeQuietly(tarIn);
            }
        }
    } catch (IOException e) {
        throw new ArchiveExtractionException("Could not extract archive: '"
                + archive
                + "'", e);
    }
