private static void extractFiles(File archive, File outputDir, Collection<String> filePatterns)
        throws IOException
    {
        if (archive.isDirectory()) {
            throw new IllegalArgumentException("Archive must be a file, not a directory: " + archive);
        }
        if (!outputDir.isDirectory()) {
            throw new IllegalArgumentException("Output directory does not eist: " + outputDir);
        }

        if (archive.getName().endsWith(".zip")) {
            extractZip(archive, outputDir, filePatterns);
        }
        else if (archive.getName().endsWith(".msi")) {
            extractMsi(archive, outputDir, filePatterns);
        }
        else if (archive.getName().endsWith(".tar.gz") || archive.getName().endsWith(".tgz")) {
            extractTarGz(archive, outputDir, filePatterns);
        }
        else {
            throw new IOException("Unable to extract files from archive: " + archive + ", unrecognized extension");
        }
    }

