private void writeTo(final File destination) throws IOException {
    if (!destination.getParentFile().exists()) {
      if (!destination.getParentFile().mkdirs()) {
        throw new IOException("Could not create directory " + destination.getParentFile().getAbsolutePath());
      }
    }

    final FileOutputStream outStream;
    final boolean closeStream;
    if (destination.getPath().startsWith(getAbsolutePath())) {
      throw new IOException("Cannot write file " + getAbsolutePath() + " to itself.");
    } else if (destination.getCanonicalPath().startsWith(getAbsolutePath())) {
      throw new IOException("Cannot write file " + getAbsolutePath() + " to " + destination.getCanonicalPath());
    } else if (destination.isDirectory()) {
      outStream = new FileOutputStream(new File(destination, name));
      closeStream = true;
    } else {
      outStream = new FileOutputStream(destination);
      closeStream = true;
    }

    try {
      writeTo(outStream);
    } finally {
      if (closeStream) {
        outStream.close();
      }
    }
  }

