private void updateModule( final ModuleBean module, final boolean external, final boolean repair ) {
	LEnv.LOGGER.info( ( repair ? "Repairing " : "Updating " ) + module.getName() + "..." );
	launcherFrame.setStatus( StatusType.PROGRESS, ( repair ? "Repairing " : "Updating " ) + module.getName() );

	if ( module == modules.getLauncherMod() ) {
		// Launcher update requires restart, show RESTART action while updating the launcher
		launcherFrame.setProceedText( "<html><h2>RE_START</h2></html>" );
	}

	final Path tempPath = ( external ? LEnv.PATH_EXT_MODS : LEnv.PATH_MODS ).resolve( "_update" );
	try {
		// Create temp update folder
		while ( !LUtils.deletePath( tempPath ) )
			if ( !LGuiUtils.askRetry( "Could not delete folder:", tempPath ) )
				throw new Exception( "Could not delete folder: " + tempPath );
		Files.createDirectory( tempPath );

		final Path archivePath = tempPath.resolve( module.getArchiveFile().getPath() );

		// Download module archive, try mirrors if one fails
		final byte[] buffer = new byte[ 16_384 ]; // 16 KB work buffer
		for ( int urlIdx = 0; urlIdx < module.getUrlList().size(); urlIdx++ ) {
			final String archiveSource = urlIdx == 0 ? "main source" : " mirror #" + urlIdx;
			final boolean lastArchiveUrl = urlIdx == module.getUrlList().size() - 1;

			LEnv.LOGGER.debug( "Downloading archive from " + archiveSource + "..." );

			boolean downloadOk = false;
			InputStream input = null;
			OutputStream output = null;
			try {
				LEnv.LOGGER.debug( "Connecting..." );
				launcherFrame.setProgressMax( (int) module.getArchiveSize() );
				launcherFrame.setProgress( 0 );

				input = new BufferedInputStream( new URL( module.getUrlList().get( urlIdx ) ).openStream() );
				output = new BufferedOutputStream( Files.newOutputStream( archivePath ) );

				int read;
				while ( ( read = input.read( buffer ) ) != -1 ) {
					output.write( buffer, 0, read );
					launcherFrame.setProgress( (int) ( ( (double) output.getChannel().position() / (double) module.getArchiveSize() ) * 100 ) );
				}

				output.flush();
				output.close();
				output = null;

				input.close();
				input = null;

				downloadOk = true;

				LEnv.LOGGER.debug( "Download complete." );

				break;
			} catch ( final Exception e ) {
				if ( lastArchiveUrl ) {
					LEnv.LOGGER.error( "Could not download archive from " + archiveSource + ": " + e.getMessage() );
					throw new Exception( "Could not download archive from " + archiveSource + ": " + e.getMessage() );
				}

				LEnv.LOGGER.error( "Could not download archive from " + archiveSource + ": " + e.getMessage() );
				LEnv.LOGGER.debug( "Trying next mirror..." );
			} finally {
				if ( input != null )
					input.close();
				if ( output != null )
					output.close();
			}
		}

		// Extract module archive
		LEnv.LOGGER.debug( "Extracting archive..." );
		launcherFrame.setProgressMax( 100 );
		launcherFrame.setProgress( 0 );

		final Path extractPath = tempPath.resolve( module.getExtractPath() );

		if ( !Files.exists( extractPath ) )
			Files.createDirectory( extractPath );

		final ZipFile zipFile = new ZipFile( archivePath.toFile() );
		final Enumeration<? extends ZipEntry> entries = zipFile.entries();

		while ( entries.hasMoreElements() ) {
			final ZipEntry entry = entries.nextElement();

			if ( entry.isDirectory() )
				continue;

			final Path entryPath = extractPath.resolve( entry.getName() );

			if ( !Files.exists( entryPath.getParent() ) )
				Files.createDirectories( entryPath.getParent() );

			try ( final InputStream entryStream = zipFile.getInputStream( entry ) ) {
				Files.copy( entryStream, entryPath, StandardCopyOption.REPLACE_EXISTING );
			}

			launcherFrame.setProgress( (int) ( ( (double) Files.size( entryPath ) / (double) module.getArchiveSize() ) * 100 ) );
		}

		zipFile.close();

		// Replace module files
		LEnv.LOGGER.debug( "Replacing files..." );

		final Path modulePath = external ? LEnv.PATH_EXT_MODS : LEnv.PATH_MODS;

		for ( final Path file : Files.newDirectoryStream( extractPath ) ) {
			final Path target = modulePath.resolve( file.getFileName() );

			if ( Files.exists( target ) )
				Files.delete( target );

			Files.move( file, target );
		}

		// Delete temp folder
		LUtils.deletePath( tempPath );

		// Update module info
		module.setVersion( module.getVersion() + ( repair ? " (repair)" : " (update)" ) );
		module.setArchiveFile( null );
		module.setArchiveSize( 0 );

		if ( module == modules.getLauncherMod() ) {
			// Launcher update requires restart, show RESTART action while updating the launcher
			launcherFrame.setProceedText( "<html><h2>RE_START</h2></html>" );
		}

		LEnv.LOGGER.info( "Update complete." );
		launcherFrame.setStatus( StatusType.READY, "Update complete." );
	} catch ( final Exception e ) {
		LEnv.LOGGER.error( "Could not update module: " + e.getMessage() );
		launcherFrame.setStatus( StatusType.ERROR, "Could not update module: " + e.getMessage() );
	}
}

