def security_check_relative_path_in_directory(directory, relative_path):
    """
    Returns the relative path if it is in the directory or its subdirectories.
    Raises an error if the relative path tries to go outside of the directory.
    """
    if not relative_path.startswith(os.path.sep):
        relative_path = os.path.sep + relative_path
    path = os.path.join(directory, relative_path)
    if not path.startswith(directory + os.path.sep):
        raise Exception(
            "Security error detected: Attempt to access a path outside of the target directory"
        )
    return path[len(directory) + 1 :]

