def parse_jeos_config(self, source):

    jeos_config = {}

    for line in source:
        line = line.strip()

        # Ignore comments
        if line.startswith('#'):
            continue

        # Ignore blank lines
        if not line:
            continue

        try:
            key, value = line.split('=')
        except ValueError:
            continue

        key = key.strip()
        value = value.strip()

        if key in ('default', 'include', 'log_level', 'root'):
            continue

        jeos_config[key] = value

    return jeos_config

