def replace_directory(old_dir, new_dir):
    """
    Function to replace a source directory with a destination directory,
    adjusting permissions for webserver access.
    """
    import shutil
    import stat
    from os.path import join

    for root, dirs, files in os.walk(new_dir):
        for d in dirs:
            path = join(root, d)
            old = join(old_dir, path[len(new_dir):])
            if os.path.exists(old):
                shutil.rmtree(path)
                print "Removed %s" % path
            else:
                print "Creating %s" % path
                os.makedirs(path)
              # Apply old permissions
            for f in files:
                path = join(root, f)
                old = join(old_dir, path[len(new_dir):])
                if os.path.exists(old):
                    # Apply old permissions
                    st = os.stat(old)
                    print "Restoring permissions of %s to %04o" % (path, st.st_mode & 07777)
                    os.chmod(path, st.st_mode & 07777)
                else:
                    print "Creating %s" % path

    for root, dirs, files in os.walk(old_dir):
        for d in dirs:
            path = join(root, d)
            new = join(new_dir, path[len(old_dir):])
            if not os.path.exists(new):
                print "Removing %s" % path
                shutil.rmtree(path)
        for f in files:
            path = join(root, f)
            new = join(new_dir, path[len(old_dir):])
            if not os.path.exists(new):
                print "Removing %s" % path
                os.remove(path)

