git_info(path, content)
	char *path;
	void *content;
{
	int is_dir;
	char *cp;
	struct stat st;
	char *result;
	char *format;

	is_dir = is_directory(content);
	if (is_dir && asprintf(&cp, "%s/%s", path, GIT_DIR) >= 0 &&
	    lstat(cp, &st) != -1 && S_ISDIR(st.st_mode)) {
		format = "%s (git:%s)";
		result = alloc(st.st_size + strlen(path) + strlen(format) + 2);
		sprintf(result, format, path, cp);
		free(cp);
	} else if (!is_dir && lstat(path, &st) != -1) {
		if (S_ISGITLINK(st.st_mode)) {
			format = "%s (git:%s)";
			result = alloc(st.st_size + strlen(path) + strlen(format) + 2);
			sprintf(result, format, path, git_path(path));
		} else {
			format = "%s (not a git repository)";
			result = alloc(st.st_size + strlen(path) + strlen(format) + 2);
			sprintf(result, format, path);
		}
	} else {
		format = "%s (no git repository here)";
		result = alloc(strlen(path) + strlen(format) + 2);
		sprintf(result, format, path);
	}
	return result;
}

