        case AF_INET6: {
            auto *addr = (struct sockaddr_in6 *)&sock->sa_local;
            inet_ntop(AF_INET6, &(addr->sin6_addr), sock->ep_local, sizeof(sock->ep_local));
            strncpy(sock->ep_local2.host, sock->ep_local, sizeof(sock->ep_local2.host));
