pdf_add_bookmark(PDF *pdf, const char *name, int page, int hidden)
{
  pdf_obj *tmp, *tmp2, *dict;

  if (pdf_find_bookmark(pdf, name, page) != NULL)
    return NULL;
  if (pdf->catalog->Version < 14)
    pdf_set_version(pdf, 1, 4);
  dict = pdf_new_dict(pdf);
  if (hidden)
    pdf_add_dict(dict, pdf_new_name(pdf, "F"), pdf_new_int(pdf, 0));
  tmp = pdf_new_string(pdf, name);
  pdf_add_dict(dict, pdf_new_name(pdf, "N"), tmp);
  tmp2 = pdf_new_number(pdf, page);
  pdf_add_dict(dict, pdf_new_name(pdf, "P"), tmp2);
  pdf_add_dict(pdf->catalog, pdf_new_name(pdf, "D"), dict);
  return dict;
}

