int bt_gatt_register_ccc_callback(struct bt_gatt_client *client,
				       const bt_uuid_t *uuid,
				       bt_gatt_ccc_callback_t callback,
				       void *user_data)
{
	struct bt_gatt_ccc_cfg *cfg;
	int i, id;

	for (i = 0; i < client->num_ccc_cfgs; i++) {
		cfg = &client->ccc_cfgs[i];

		if (!bt_uuid_cmp(cfg->uuid, uuid)) {
			cfg->value_changed = callback;
			cfg->user_data = user_data;
			return 0;
		}
	}

	id = bt_gatt_get_available_id(client);
	if (id < 0)
		return id;

	cfg = &client->ccc_cfgs[id];
	bt_gatt_dup_uuid(&cfg->uuid, uuid);
	cfg->value_changed = callback;
	cfg->user_data = user_data;
	cfg->id = id;
	client->num_ccc_cfgs++;

	return id;
}
